INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'listening', 'At the Doctor', 'A dialogue during a clinic visit.', '{"type":"listen_and_choose","instructions":"Listen and answer based on the conversation.","exercises":[{"prompt":"Good morning. I feel very weak and have a slight fever.","question":"How does the patient feel?","options":["Strong","Weak","Hungry"],"correct":1,"hint":"Listen for ''weak''."},{"prompt":"Let me check your temperature. It is 38.5 degrees.","question":"What is the temperature?","options":["36.5","37.5","38.5"],"correct":2,"hint":"Number check."},{"prompt":"I also have a sore throat since yesterday evening.","question":"When did the sore throat start?","options":["Yesterday morning","Yesterday evening","This morning"],"correct":1,"hint":"Timing words."},{"prompt":"Take this medicine twice a day after meals.","question":"How often should they take medicine?","options":["Once a day","Twice a day","Every hour"],"correct":1,"hint":"Twice means two times."},{"prompt":"Avoid cold drinks and get plenty of rest this weekend.","question":"What should they avoid?","options":["Rest","Cold drinks","Medicine"],"correct":1,"hint":"Listen for the negative."},{"prompt":"I have been coughing for three days now.","question":"How long has the patient been coughing?","options":["One day","Two days","Three days"],"correct":2,"hint":"Listen for the duration."},{"prompt":"I feel dizzy and sometimes I have headaches.","question":"What other symptom does the patient have?","options":["Nausea","Headaches","Fatigue"],"correct":1,"hint":"Listen for ''headaches''."},{"prompt":"I have a runny nose and I keep sneezing.","question":"What symptom does the patient mention?","options":["Runny nose","Sore throat","Fever"],"correct":0,"hint":"Listen for ''runny nose''."},{"prompt":"My appetite has decreased over the past week.","question":"What has happened to the patient''s appetite?","options":["Increased","Decreased","Remained the same"],"correct":1,"hint":"Listen for ''decreased''."},{"prompt":"I have trouble sleeping because of the pain.","question":"What problem does the patient have related to sleep?","options":["Sleep well","Trouble sleeping","Sleep too much"],"correct":1,"hint":"Listen for ''trouble sleeping''."},{"prompt":"I feel better after taking some medicine.","question":"How does the patient feel after taking medicine?","options":["Worse","Better","The same"],"correct":1,"hint":"Listen for ''better''."},{"prompt":"I have a rash on my arms and legs.","question":"Where is the rash located?","options":["On the face","On the arms and legs","On the stomach"],"correct":1,"hint":"Listen for ''arms and legs''."},{"prompt":"I feel nauseous after eating.","question":"How does the patient feel after eating?","options":["Hungry","Tired","Nauseous"],"correct":2,"hint":"Listen for ''nauseous''."},{"prompt":"I have been experiencing chest pain.","question":"What type of pain is the patient experiencing?","options":["Back pain","Chest pain","Head pain"],"correct":1,"hint":"Listen for ''chest pain''."},{"prompt":"I often feel tired throughout the day.","question":"What does the patient often feel?","options":["Energetic","Tired","Happy"],"correct":1,"hint":"Listen for ''tired''."},{"prompt":"I have a headache that won’t go away.","question":"What type of pain does the patient have?","options":["Backache","Stomachache","Headache"],"correct":2,"hint":"Listen for ''headache''."},{"prompt":"I feel itchy all over my body.","question":"What sensation does the patient feel?","options":["Pain","Itchy","Numb"],"correct":1,"hint":"Listen for ''itchy''."},{"prompt":"I have been feeling very anxious lately.","question":"What feeling does the patient report?","options":["Calm","Happy","Anxious"],"correct":2,"hint":"Listen for ''anxious''."},{"prompt":"I have noticed swelling in my feet.","question":"What part of the body is swollen?","options":["Hands","Feet","Face"],"correct":1,"hint":"Listen for ''feet''."},{"prompt":"I have had a fever for two days.","question":"How many days has the patient had a fever?","options":["One day","Two days","Three days"],"correct":1,"hint":"Listen for ''two days''."}]}', 11),
('en', 'A2', 'listening', 'Grocery Shopping List', 'Identifying specific items from a list.', '{"type":"listen_and_choose","instructions":"Which item is needed?","exercises":[{"prompt":"We are out of butter, so buy two packs.","question":"What to buy?","options":["Milk","Butter","Cheese"],"correct":1,"hint":"Fatty dairy product."},{"prompt":"Get some sparkling water, not the still one.","question":"Which water?","options":["Still","Sparkling","Tap"],"correct":1,"hint":"Water with bubbles."},{"prompt":"Make sure the eggs are fresh and brown.","question":"What color eggs?","options":["White","Brown","Blue"],"correct":1,"hint":"Natural egg color."},{"prompt":"I need olive oil for the salad dressing.","question":"What kind of oil?","options":["Sunflower","Olive","Coconut"],"correct":1,"hint":"Mediterranean oil."},{"prompt":"Don''t forget to pick up some dark chocolate.","question":"Which chocolate type?","options":["Milk","White","Dark"],"correct":2,"hint":"Higher cocoa content."},{"prompt":"We need some fresh basil for the pasta dish.","question":"What herb?","options":["Oregano","Basil","Thyme"],"correct":1,"hint":"A fragrant green herb."},{"prompt":"Don''t forget to grab a loaf of whole grain bread.","question":"What type of bread?","options":["White","Whole grain","Rye"],"correct":1,"hint":"Bread made from whole grains."},{"prompt":"We need some ripe bananas for the smoothie.","question":"What fruit?","options":["Apples","Bananas","Grapes"],"correct":1,"hint":"Yellow fruit that''s soft inside."},{"prompt":"Please buy a dozen red roses for the event.","question":"What color roses?","options":["Yellow","Blue","Red"],"correct":2,"hint":"Color associated with love."},{"prompt":"We need some cheddar cheese for the nachos.","question":"What type of cheese?","options":["Mozzarella","Feta","Cheddar"],"correct":2,"hint":"A popular cheese for melting."},{"prompt":"Pick up some green apples at the store.","question":"What color apples?","options":["Red","Yellow","Green"],"correct":2,"hint":"Sourer than the red variety."},{"prompt":"We need a gallon of orange juice for breakfast.","question":"What drink?","options":["Apple juice","Orange juice","Grape juice"],"correct":1,"hint":"Citrus breakfast beverage."},{"prompt":"Make sure to get some fresh spinach for the salad.","question":"What leafy green?","options":["Kale","Spinach","Lettuce"],"correct":1,"hint":"Common salad ingredient."},{"prompt":"Buy a pack of dark chocolate for dessert.","question":"What type of chocolate?","options":["Milk chocolate","White chocolate","Dark chocolate"],"correct":2,"hint":"Chocolate with higher cocoa content."},{"prompt":"We need some almond milk for the coffee.","question":"What type of milk?","options":["Cow''s milk","Soy milk","Almond milk"],"correct":2,"hint":"Nut-based milk alternative."},{"prompt":"Get some fresh strawberries for the dessert.","question":"What fruit?","options":["Blueberries","Strawberries","Raspberries"],"correct":1,"hint":"Red berry with seeds on the outside."},{"prompt":"We need a bottle of olive oil for cooking.","question":"What type of oil?","options":["Vegetable oil","Canola oil","Olive oil"],"correct":2,"hint":"Oil often used in Mediterranean dishes."},{"prompt":"Pick up some ground coffee for the morning brew.","question":"What type of product?","options":["Tea","Ground coffee","Instant coffee"],"correct":1,"hint":"Beverage made from roasted beans."},{"prompt":"We need to buy some whole wheat pasta for dinner.","question":"What type of pasta?","options":["Regular pasta","Whole wheat pasta","Gluten-free pasta"],"correct":1,"hint":"Pasta made from whole grain flour."}]}', 12),
('en', 'A2', 'listening', 'The News Snippet', 'Identifying key information in a report.', '{"type":"listen_and_choose","instructions":"Find the key fact.","exercises":[{"prompt":"The city marathon will start at 7am tomorrow morning.","question":"What event is happening?","options":["Concert","Marathon","Fair"],"correct":1,"hint":"Running event."},{"prompt":"Heavy rain is expected in the northern areas.","question":"Where will it rain?","options":["South","East","North"],"correct":2,"hint":"Direction."},{"prompt":"A new library opened on Main Street yesterday.","question":"What building opened?","options":["School","Library","Gym"],"correct":1,"hint":"Book place."},{"prompt":"Public transport is free for students this week.","question":"Who gets free transport?","options":["Seniors","Students","Children"],"correct":1,"hint":"School goers."},{"prompt":"The local team won the game by two points.","question":"By how much did they win?","options":["1","2","3"],"correct":1,"hint":"Number hearing."},{"prompt":"The new art exhibit opens at the gallery this weekend.","question":"What is opening?","options":["Museum","Exhibit","Theater"],"correct":1,"hint":"Place for viewing art."},{"prompt":"A food festival will take place in the city park next Saturday.","question":"What event is happening?","options":["Market","Festival","Concert"],"correct":1,"hint":"Celebration of food."},{"prompt":"The football match will start at 5pm on Sunday.","question":"What sport is being played?","options":["Basketball","Football","Baseball"],"correct":1,"hint":"Game with a round ball."},{"prompt":"The library will close early at 4pm today.","question":"What is closing?","options":["Library","Store","School"],"correct":0,"hint":"Place for reading."},{"prompt":"There will be a science fair at the high school next Friday.","question":"What event is happening?","options":["Art fair","Science fair","Book fair"],"correct":1,"hint":"Focus on experiments."},{"prompt":"A concert featuring local bands is scheduled for next month.","question":"What type of event is it?","options":["Concert","Festival","Exhibition"],"correct":0,"hint":"Live music performance."},{"prompt":"A new bakery opened downtown last week.","question":"What kind of business opened?","options":["Bakery","Restaurant","Cafe"],"correct":0,"hint":"Place for bread and pastries."},{"prompt":"The community center offers yoga classes every Thursday evening.","question":"What type of class is offered?","options":["Dance","Yoga","Art"],"correct":1,"hint":"Relaxing exercise."},{"prompt":"An outdoor movie night will be held in the park next weekend.","question":"What event is happening?","options":["Movie night","Picnic","Game night"],"correct":0,"hint":"Watching films outside."},{"prompt":"The annual book fair is coming up next month at the convention center.","question":"What event is happening?","options":["Art show","Book fair","Craft fair"],"correct":1,"hint":"Focus on literature."},{"prompt":"The annual charity run will take place in the city on April 10th.","question":"What type of event is it?","options":["Run","Walk","Bike ride"],"correct":0,"hint":"Running for a cause."},{"prompt":"A technology workshop will be held at the library next Tuesday.","question":"What type of event is happening?","options":["Workshop","Seminar","Conference"],"correct":0,"hint":"Hands-on learning."},{"prompt":"The city council meeting will discuss new park developments.","question":"What is being discussed?","options":["New roads","Park developments","School projects"],"correct":1,"hint":"Outdoor space improvements."},{"prompt":"The farmer''s market opens every Sunday morning downtown.","question":"What is opening?","options":["Market","Store","Festival"],"correct":0,"hint":"Place for fresh produce."},{"prompt":"A cooking class for beginners starts next Wednesday evening.","question":"What type of class is it?","options":["Art class","Cooking class","Dance class"],"correct":1,"hint":"Learning to prepare food."}]}', 13),
('en', 'A2', 'listening', 'Ordering at a Restaurant', 'Complex meal choices.', '{"type":"listen_and_choose","instructions":"What is the order detail?","exercises":[{"prompt":"I would like the grilled salmon with steamed vegetables.","question":"What is the main course?","options":["Chicken","Salmon","Pasta"],"correct":1,"hint":"Fish."},{"prompt":"Could I have fries instead of salad?","question":"What does the customer prefer?","options":["Salad","Fries","Rice"],"correct":1,"hint":"Potato item."},{"prompt":"I am allergic to nuts, please check the ingredients.","question":"What is the allergy?","options":["Dairy","Nuts","Gluten"],"correct":1,"hint":"Nut warning."},{"prompt":"The table for four is ready in the garden.","question":"Where is the table?","options":["Inside","Balcony","Garden"],"correct":2,"hint":"Outdoor area."},{"prompt":"I''ll have a glass of red wine, please.","question":"What drink?","options":["Beer","Wine","Water"],"correct":1,"hint":"Grape drink."},{"prompt":"I would like a large pepperoni pizza with extra cheese.","question":"What type of pizza is ordered?","options":["Vegetarian","Pepperoni","Mushroom"],"correct":1,"hint":"Contains meat."},{"prompt":"Can I get a glass of red wine with my steak?","question":"What beverage does the customer want?","options":["White wine","Beer","Red wine"],"correct":2,"hint":"Type of wine."},{"prompt":"I would prefer the chocolate cake for dessert, please.","question":"What dessert is the customer choosing?","options":["Cheesecake","Chocolate cake","Ice cream"],"correct":1,"hint":"Contains chocolate."},{"prompt":"Could I substitute the rice for quinoa?","question":"What is the customer substituting?","options":["Pasta","Rice","Bread"],"correct":1,"hint":"Grain option."},{"prompt":"I would like my burger without pickles, please.","question":"What does the customer want removed?","options":["Onions","Pickles","Lettuce"],"correct":1,"hint":"Common topping."},{"prompt":"Can I have a cappuccino instead of a latte?","question":"What type of coffee does the customer prefer?","options":["Latte","Cappuccino","Espresso"],"correct":1,"hint":"Foamy coffee."},{"prompt":"I would like my steak medium rare, please.","question":"How does the customer want their steak cooked?","options":["Well done","Medium rare","Medium"],"correct":1,"hint":"Cooking preference."},{"prompt":"Can I get a side of garlic bread with my pasta?","question":"What side dish does the customer want?","options":["Garlic bread","Salad","Fries"],"correct":0,"hint":"Bread item."},{"prompt":"I''d like a smoothie with banana and spinach, please.","question":"What fruit is included in the smoothie?","options":["Strawberry","Mango","Banana"],"correct":2,"hint":"Yellow fruit."},{"prompt":"Can I have the vegan burger instead of the beef burger?","question":"What type of burger does the customer choose?","options":["Chicken burger","Beef burger","Vegan burger"],"correct":2,"hint":"Plant-based option."},{"prompt":"I would like a bowl of spicy ramen, please.","question":"What type of noodle dish is ordered?","options":["Sushi","Ramen","Udon"],"correct":1,"hint":"Japanese noodle soup."},{"prompt":"Could I get a plain bagel with cream cheese?","question":"What type of bagel does the customer want?","options":["Sesame","Plain","Everything"],"correct":1,"hint":"No toppings."},{"prompt":"I would like a tall glass of iced tea, please.","question":"What drink is ordered?","options":["Lemonade","Iced tea","Hot tea"],"correct":1,"hint":"Cold beverage."},{"prompt":"I would like my sandwich toasted, please.","question":"How does the customer want their sandwich?","options":["Cold","Toasted","With extra mayo"],"correct":1,"hint":"Heated option."},{"prompt":"Can I have a side of coleslaw with that?","question":"What side dish is requested?","options":["Coleslaw","Potato salad","Fruit salad"],"correct":0,"hint":"Cabbage salad."}]}', 14),
('en', 'A2', 'listening', 'Travel Announcements', 'Train and airport info.', '{"type":"listen_and_choose","instructions":"What info is given?","exercises":[{"prompt":"The train to London is delayed by fifteen minutes.","question":"How long is the delay?","options":["5 mins","10 mins","15 mins"],"correct":2,"hint":"Listen for 15."},{"prompt":"Please go to gate 42 for boarding.","question":"Which gate?","options":["24","42","52"],"correct":1,"hint":"Number reversal risk."},{"prompt":"Keep your bags with you at all times.","question":"What to keep?","options":["Bags","Phones","Tickets"],"correct":0,"hint":"Luggage."},{"prompt":"Platform three is closed for maintenance.","question":"Which platform is closed?","options":["2","3","4"],"correct":1,"hint":"Number."},{"prompt":"The next flight departs at six forty-five.","question":"Departure time?","options":["6:15","6:45","7:15"],"correct":1,"hint":"Quarter to seven."},{"prompt":"The meeting starts at 3 PM sharp.","question":"What time does the meeting start?","options":["2 PM","3 PM","4 PM"],"correct":1,"hint":"Listen for the hour."},{"prompt":"Your package will arrive on Tuesday.","question":"When will the package arrive?","options":["Monday","Tuesday","Wednesday"],"correct":1,"hint":"Listen for the day of the week."},{"prompt":"The museum is closed on Mondays.","question":"Which day is the museum closed?","options":["Saturday","Monday","Thursday"],"correct":1,"hint":"A common closing day."},{"prompt":"There is a sale on shoes this weekend.","question":"What is on sale?","options":["Clothes","Shoes","Bags"],"correct":1,"hint":"Footwear focus."},{"prompt":"Please turn off your mobile phones.","question":"What should you turn off?","options":["Laptops","Mobile phones","Tablets"],"correct":1,"hint":"Electronic devices."},{"prompt":"The concert starts at 8 PM.","question":"What time does the concert start?","options":["6 PM","7 PM","8 PM"],"correct":2,"hint":"Evening event."},{"prompt":"Please fill out this form completely.","question":"What should you fill out?","options":["Form","Application","Survey"],"correct":0,"hint":"Official document."},{"prompt":"The bakery is famous for its chocolate cake.","question":"What is the bakery famous for?","options":["Bread","Chocolate cake","Cookies"],"correct":1,"hint":"Sweet treat."},{"prompt":"The flight to New York is on time.","question":"How is the flight to New York?","options":["Delayed","On time","Canceled"],"correct":1,"hint":"Punctuality."},{"prompt":"There will be a fire drill at noon.","question":"When is the fire drill scheduled?","options":["10 AM","12 PM","1 PM"],"correct":1,"hint":"Midday event."},{"prompt":"Please submit your assignment by Friday.","question":"When is the assignment due?","options":["Wednesday","Friday","Saturday"],"correct":1,"hint":"Week''s end."},{"prompt":"The library opens at 9 AM.","question":"What time does the library open?","options":["8 AM","9 AM","10 AM"],"correct":1,"hint":"Morning hours."},{"prompt":"The restaurant is located on Main Street.","question":"Where is the restaurant located?","options":["Second Avenue","Main Street","First Avenue"],"correct":1,"hint":"Street name."},{"prompt":"The doctor will see you now.","question":"Who will see you now?","options":["Nurse","Doctor","Receptionist"],"correct":1,"hint":"Medical professional."},{"prompt":"The show lasts for two hours.","question":"How long does the show last?","options":["1 hour","2 hours","3 hours"],"correct":1,"hint":"Duration of entertainment."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'speaking', 'Narrating the Past', 'Describe a yesterday event.', '{"type":"speak_and_repeat","instructions":"Narrate the sentence in past tense.","exercises":[{"prompt":"Yesterday, I went to the park with my dog.","expected":"Yesterday I went to the park with my dog","hint":"Past of go."},{"prompt":"I saw a very famous singer at the mall.","expected":"I saw a very famous singer at the mall","hint":"Past of see."},{"prompt":"We ate dinner at a small Italian restaurant.","expected":"We ate dinner at a small Italian restaurant","hint":"Past of eat."},{"prompt":"I finished my homework late last night.","expected":"I finished my homework late last night","hint":"Past of finish."},{"prompt":"It was a very beautiful and sunny day.","expected":"It was a very beautiful and sunny day","hint":"Past condition."},{"prompt":"Last weekend, I visited my grandparents in the countryside.","expected":"Last weekend I visited my grandparents in the countryside","hint":"Past of visit."},{"prompt":"She finished her homework before dinner.","expected":"She finished her homework before dinner","hint":"Past of finish."},{"prompt":"They traveled to Spain for their vacation.","expected":"They traveled to Spain for their vacation","hint":"Past of travel."},{"prompt":"He bought a new bicycle last month.","expected":"He bought a new bicycle last month","hint":"Past of buy."},{"prompt":"I read an interesting book last summer.","expected":"I read an interesting book last summer","hint":"Past of read."},{"prompt":"We played soccer at the park yesterday.","expected":"We played soccer at the park yesterday","hint":"Past of play."},{"prompt":"She wrote a letter to her friend.","expected":"She wrote a letter to her friend","hint":"Past of write."},{"prompt":"They watched a movie together on Friday night.","expected":"They watched a movie together on Friday night","hint":"Past of watch."},{"prompt":"I took a lot of pictures during my trip.","expected":"I took a lot of pictures during my trip","hint":"Past of take."},{"prompt":"He spoke at the conference last year.","expected":"He spoke at the conference last year","hint":"Past of speak."},{"prompt":"We danced at the party until midnight.","expected":"We danced at the party until midnight","hint":"Past of dance."},{"prompt":"She sang her favorite song at the karaoke bar.","expected":"She sang her favorite song at the karaoke bar","hint":"Past of sing."},{"prompt":"I found my lost keys under the couch.","expected":"I found my lost keys under the couch","hint":"Past of find."},{"prompt":"They cleaned the house together on Saturday.","expected":"They cleaned the house together on Saturday","hint":"Past of clean."},{"prompt":"He learned to play the guitar as a child.","expected":"He learned to play the guitar as a child","hint":"Past of learn."}]}', 11),
('en', 'A2', 'speaking', 'Giving Reasons', 'Use ''because'' in speech.', '{"type":"speak_and_repeat","instructions":"Connect the reason clearly.","exercises":[{"prompt":"I am happy because I passed my exam.","expected":"I am happy because I passed my exam","hint":"Emotion plus reason."},{"prompt":"I stayed home because it was raining.","expected":"I stayed home because it was raining","hint":"Action plus reason."},{"prompt":"He is tired because he worked all night.","expected":"He is tired because he worked all night","hint":"Status plus reason."},{"prompt":"We went out because we were hungry.","expected":"We went out because we were hungry","hint":"Motivation."},{"prompt":"I like English because it is useful.","expected":"I like English because it is useful","hint":"Preference."},{"prompt":"She is excited because she is going on vacation.","expected":"She is excited because she is going on vacation","hint":"Emotion plus reason."},{"prompt":"They left early because they wanted to avoid traffic.","expected":"They left early because they wanted to avoid traffic","hint":"Action plus reason."},{"prompt":"I feel sad because my friend moved away.","expected":"I feel sad because my friend moved away","hint":"Emotion plus reason."},{"prompt":"He is studying hard because he wants to get a scholarship.","expected":"He is studying hard because he wants to get a scholarship","hint":"Action plus reason."},{"prompt":"She is nervous because she has a job interview.","expected":"She is nervous because she has a job interview","hint":"Emotion plus reason."},{"prompt":"I went for a walk because I needed some fresh air.","expected":"I went for a walk because I needed some fresh air","hint":"Action plus reason."},{"prompt":"They are proud because they won the championship.","expected":"They are proud because they won the championship","hint":"Emotion plus reason."},{"prompt":"We decided to stay home because it was too cold outside.","expected":"We decided to stay home because it was too cold outside","hint":"Action plus reason."},{"prompt":"I am grateful because I have supportive friends.","expected":"I am grateful because I have supportive friends","hint":"Emotion plus reason."},{"prompt":"He is happy because he got a promotion.","expected":"He is happy because he got a promotion","hint":"Emotion plus reason."},{"prompt":"She studied all night because she has a big exam tomorrow.","expected":"She studied all night because she has a big exam tomorrow","hint":"Action plus reason."},{"prompt":"I feel relaxed because I finished my project.","expected":"I feel relaxed because I finished my project","hint":"Emotion plus reason."},{"prompt":"They are celebrating because it''s their anniversary.","expected":"They are celebrating because it''s their anniversary","hint":"Emotion plus reason."},{"prompt":"I called my parents because I wanted to check on them.","expected":"I called my parents because I wanted to check on them","hint":"Action plus reason."},{"prompt":"He is frustrated because his computer is not working.","expected":"He is frustrated because his computer is not working","hint":"Emotion plus reason."},{"prompt":"We went to the beach because it was a sunny day.","expected":"We went to the beach because it was a sunny day","hint":"Action plus reason."}]}', 12),
('en', 'A2', 'speaking', 'Future Plans', 'Talk about upcoming events.', '{"type":"speak_and_repeat","instructions":"State your future plan.","exercises":[{"prompt":"I am going to visit my parents next week.","expected":"I am going to visit my parents next week","hint":"Going to future."},{"prompt":"We will travel to Japan in the summer.","expected":"We will travel to Japan in the summer","hint":"Will future."},{"prompt":"She is starting a new job tomorrow morning.","expected":"She is starting a new job tomorrow morning","hint":"Present continuous as future."},{"prompt":"I hope to buy a new car soon.","expected":"I hope to buy a new car soon","hint":"Aspiration."},{"prompt":"They are planning a big party for Saturday.","expected":"They are planning a big party for Saturday","hint":"Social plan."},{"prompt":"I am going to start a new exercise routine next month.","expected":"I am going to start a new exercise routine next month","hint":"Going to future."},{"prompt":"They will have a meeting next Friday.","expected":"They will have a meeting next Friday","hint":"Will future."},{"prompt":"He is moving to a new apartment next week.","expected":"He is moving to a new apartment next week","hint":"Present continuous as future."},{"prompt":"We are going to celebrate our anniversary in July.","expected":"We are going to celebrate our anniversary in July","hint":"Going to future."},{"prompt":"She will graduate from college next year.","expected":"She will graduate from college next year","hint":"Will future."},{"prompt":"I am taking a vacation in December.","expected":"I am taking a vacation in December","hint":"Present continuous as future."},{"prompt":"You are going to learn a new language this year.","expected":"You are going to learn a new language this year","hint":"Going to future."},{"prompt":"We will visit our friends over the weekend.","expected":"We will visit our friends over the weekend","hint":"Will future."},{"prompt":"They are starting a new project next month.","expected":"They are starting a new project next month","hint":"Present continuous as future."},{"prompt":"I am going to bake a cake for the party.","expected":"I am going to bake a cake for the party","hint":"Going to future."},{"prompt":"She will join us for dinner tomorrow.","expected":"She will join us for dinner tomorrow","hint":"Will future."},{"prompt":"He is taking a day off next week.","expected":"He is taking a day off next week","hint":"Present continuous as future."},{"prompt":"We are going to watch a movie this weekend.","expected":"We are going to watch a movie this weekend","hint":"Going to future."},{"prompt":"I will call you later this evening.","expected":"I will call you later this evening","hint":"Will future."},{"prompt":"They are planning to travel to Europe next summer.","expected":"They are planning to travel to Europe next summer","hint":"Present continuous as future."}]}', 13),
('en', 'A2', 'speaking', 'Asking for Advice', 'Requests for suggestions.', '{"type":"speak_and_repeat","instructions":"Ask for advice clearly.","exercises":[{"prompt":"What should I wear for the interview?","expected":"What should I wear for the interview","hint":"Using should."},{"prompt":"Where do you think is the best place to eat?","expected":"Where do you think is the best place to eat","hint":"Asking opinion."},{"prompt":"How can I improve my English speaking?","expected":"How can I improve my English speaking","hint":"Asking for help."},{"prompt":"Could you recommend a good movie to watch?","expected":"Could you recommend a good movie to watch","hint":"Requesting recommendation."},{"prompt":"Do you think I should buy this jacket?","expected":"Do you think I should buy this jacket","hint":"Check for opinion."},{"prompt":"What should I do to prepare for the exam?","expected":"What should I do to prepare for the exam","hint":"Using should."},{"prompt":"Can you recommend a good book to read?","expected":"Can you recommend a good book to read","hint":"Asking for recommendations."},{"prompt":"What would you suggest I cook for dinner?","expected":"What would you suggest I cook for dinner","hint":"Seeking cooking advice."},{"prompt":"How can I manage my time better?","expected":"How can I manage my time better","hint":"Asking for strategies."},{"prompt":"What are some tips for staying healthy?","expected":"What are some tips for staying healthy","hint":"Inquiry about health advice."},{"prompt":"Where should I go for a vacation?","expected":"Where should I go for a vacation","hint":"Seeking travel advice."},{"prompt":"How can I make new friends?","expected":"How can I make new friends","hint":"Asking for social advice."},{"prompt":"What do you think I should focus on in my career?","expected":"What do you think I should focus on in my career","hint":"Asking for career guidance."},{"prompt":"What should I do if I''m feeling stressed?","expected":"What should I do if I''m feeling stressed","hint":"Seeking emotional support."},{"prompt":"Can you help me choose a gift for my friend?","expected":"Can you help me choose a gift for my friend","hint":"Asking for gift suggestions."},{"prompt":"What are the best practices for writing a resume?","expected":"What are the best practices for writing a resume","hint":"Inquiring about job application tips."},{"prompt":"How can I save money effectively?","expected":"How can I save money effectively","hint":"Asking for financial advice."},{"prompt":"What should I do to improve my time management skills?","expected":"What should I do to improve my time management skills","hint":"Seeking improvement suggestions."},{"prompt":"Where is the best place to learn a new language?","expected":"Where is the best place to learn a new language","hint":"Asking for educational resources."},{"prompt":"How can I make a good impression on a date?","expected":"How can I make a good impression on a date","hint":"Seeking dating advice."}]}', 14),
('en', 'A2', 'speaking', 'Describing a Room', 'Use prepositions of place.', '{"type":"speak_and_repeat","instructions":"Describe the arrangement.","exercises":[{"prompt":"The lamp is on the table next to the bed.","expected":"The lamp is on the table next to the bed","hint":"On/Next to."},{"prompt":"There is a large rug under the coffee table.","expected":"There is a large rug under the coffee table","hint":"Under."},{"prompt":"The books are between the clock and the vase.","expected":"The books are between the clock and the vase","hint":"Between."},{"prompt":"My keys are inside the small blue box.","expected":"My keys are inside the small blue box","hint":"Inside."},{"prompt":"The picture is hanging above the sofa.","expected":"The picture is hanging above the sofa","hint":"Above."},{"prompt":"The cat is sleeping on the couch.","expected":"The cat is sleeping on the couch","hint":"On."},{"prompt":"The picture is hanging above the fireplace.","expected":"The picture is hanging above the fireplace","hint":"Above."},{"prompt":"There is a chair in front of the desk.","expected":"There is a chair in front of the desk","hint":"In front of."},{"prompt":"The clock is mounted on the wall.","expected":"The clock is mounted on the wall","hint":"On."},{"prompt":"The dog is under the dining table.","expected":"The dog is under the dining table","hint":"Under."},{"prompt":"The keys are beside the laptop.","expected":"The keys are beside the laptop","hint":"Beside."},{"prompt":"The shoes are next to the front door.","expected":"The shoes are next to the front door","hint":"Next to."},{"prompt":"The flowers are in the vase on the shelf.","expected":"The flowers are in the vase on the shelf","hint":"In."},{"prompt":"The blanket is folded at the foot of the bed.","expected":"The blanket is folded at the foot of the bed","hint":"At."},{"prompt":"The remote control is between the cushions.","expected":"The remote control is between the cushions","hint":"Between."},{"prompt":"The sofa is across from the television.","expected":"The sofa is across from the television","hint":"Across from."},{"prompt":"The plants are in the corner of the room.","expected":"The plants are in the corner of the room","hint":"In."},{"prompt":"The dining chairs are around the table.","expected":"The dining chairs are around the table","hint":"Around."},{"prompt":"The rug is in the center of the living room.","expected":"The rug is in the center of the living room","hint":"In."},{"prompt":"The curtains are drawn over the window.","expected":"The curtains are drawn over the window","hint":"Over."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'reading', 'The Travel Blog', 'Read about a trip to the mountains.', '{"type":"read_and_choose","instructions":"Read and answer details.","exercises":[{"sentence":"Last winter, I spent a week in the Swiss Alps. The snow was incredibly deep.","question":"Where did the person go?","options":["The beach","The mountains","The city"],"correct":1,"explanation":"Swiss Alps are mountains."},{"sentence":"I stayed in a small wooden cabin with a warm fireplace.","question":"What kind of house was it?","options":["Brick","Wooden","Stone"],"correct":1,"explanation":"Wooden cabin."},{"sentence":"Every morning, I went skiing for four hours before lunch.","question":"How long did they ski?","options":["2 hours","4 hours","all day"],"correct":1,"explanation":"Skiing for four hours."},{"sentence":"In the evenings, I drank hot chocolate and read books.","question":"What did they do in the evening?","options":["Dance","Read","Cook"],"correct":1,"explanation":"Read books."},{"sentence":"I met many interesting people from different countries there.","question":"Who did they meet?","options":["Only locals","Diverse travelers","Family"],"correct":1,"explanation":"People from different countries."},{"sentence":"During my vacation, I visited the beautiful beaches of Thailand. The water was crystal clear.","question":"Where did the person go?","options":["The mountains","The beach","The forest"],"correct":1,"explanation":"Thailand is known for its beaches."},{"sentence":"I explored ancient temples and tasted delicious street food.","question":"What kind of food did they try?","options":["Fast food","Street food","Home-cooked meals"],"correct":1,"explanation":"Street food is popular in Thailand."},{"sentence":"In the evenings, I enjoyed watching the sunset over the ocean.","question":"What did they watch?","options":["The sunrise","The sunset","The stars"],"correct":1,"explanation":"They enjoyed watching the sunset."},{"sentence":"I went snorkeling in the coral reefs and saw colorful fish.","question":"What activity did they do?","options":["Snorkeling","Surfing","Fishing"],"correct":0,"explanation":"Snorkeling allows you to see fish in coral reefs."},{"sentence":"Every day, I went for a long walk along the sandy shore.","question":"What did they do daily?","options":["Run","Swim","Walk"],"correct":2,"explanation":"They walked along the shore."},{"sentence":"I took a boat tour to explore nearby islands.","question":"What mode of transportation did they use?","options":["Car","Train","Boat"],"correct":2,"explanation":"They used a boat to explore islands."},{"sentence":"The locals were friendly and shared their culture with me.","question":"How did the locals treat them?","options":["Indifferently","Friendly","Hostile"],"correct":1,"explanation":"The locals were friendly."},{"sentence":"I learned a few phrases in Thai to communicate better.","question":"What did they learn?","options":["Thai phrases","English phrases","Spanish phrases"],"correct":0,"explanation":"They learned Thai phrases."},{"sentence":"One day, I joined a cooking class to learn how to make traditional dishes.","question":"What type of class did they join?","options":["Art class","Cooking class","Dance class"],"correct":1,"explanation":"They joined a cooking class."},{"sentence":"I saw elephants in a sanctuary during my trip.","question":"What animals did they see?","options":["Dogs","Cats","Elephants"],"correct":2,"explanation":"They saw elephants in a sanctuary."},{"sentence":"The weather was warm and sunny every day.","question":"What was the weather like?","options":["Cold and rainy","Warm and sunny","Windy and cloudy"],"correct":1,"explanation":"The weather was described as warm and sunny."},{"sentence":"I bought souvenirs to remember my trip.","question":"What did they purchase?","options":["Souvenirs","Clothes","Electronics"],"correct":0,"explanation":"They bought souvenirs."},{"sentence":"I attended a traditional dance performance one evening.","question":"What kind of performance did they attend?","options":["Musical","Dance","Theater"],"correct":1,"explanation":"They attended a dance performance."},{"sentence":"I enjoyed a relaxing massage at a local spa.","question":"What service did they enjoy?","options":["Haircut","Massage","Facial"],"correct":1,"explanation":"They enjoyed a relaxing massage."},{"sentence":"Before leaving, I took many pictures to capture my memories.","question":"What did they do to remember their trip?","options":["Took pictures","Wrote a diary","Made videos"],"correct":0,"explanation":"They took pictures to capture memories."}]}', 11),
('en', 'A2', 'reading', 'Job Application Email', 'Formal communication.', '{"type":"read_and_choose","instructions":"Understand the job inquiry.","exercises":[{"sentence":"Dear Manager, I am writing to apply for the position of Sales Assistant.","question":"What job is the person applying for?","options":["Chef","Sales Assistant","Driver"],"correct":1,"explanation":"Sales Assistant."},{"sentence":"I have three years of experience in retail and customer service.","question":"How much experience do they have?","options":["1 year","2 years","3 years"],"correct":2,"explanation":"Three years."},{"sentence":"I am available to work weekends and evening shifts.","question":"When can they work?","options":["Only mornings","Evenings/Weekends","Mondays only"],"correct":1,"explanation":"Available weekends and evening shifts."},{"sentence":"Please find my resume attached to this email.","question":"What else is in the email?","options":["A photo","A resume","A letter"],"correct":1,"explanation":"Resume attached."},{"sentence":"I look forward to hearing from you. Sincerely, Jane Doe.","question":"Who is Jane Doe?","options":["The manager","The applicant"],"correct":1,"explanation":"Jane is the one writing."},{"sentence":"I am eager to join your team as a Marketing Intern.","question":"What position is the person applying for?","options":["Sales Manager","Marketing Intern","Accountant"],"correct":1,"explanation":"Marketing Intern."},{"sentence":"I have a degree in Business Administration and excellent communication skills.","question":"What is their educational background?","options":["High School Diploma","Degree in Business Administration","Certificate in Marketing"],"correct":1,"explanation":"Degree in Business Administration."},{"sentence":"I am proficient in Microsoft Office and social media marketing.","question":"What skills do they possess?","options":["Graphic Design","Microsoft Office and social media marketing","Programming"],"correct":1,"explanation":"Proficient in Microsoft Office and social media marketing."},{"sentence":"I am seeking a full-time position in the tech industry.","question":"What type of job are they looking for?","options":["Part-time","Freelance","Full-time in the tech industry"],"correct":2,"explanation":"Seeking a full-time position."},{"sentence":"I am willing to relocate for the right opportunity.","question":"What is their stance on relocation?","options":["Not willing to relocate","Willing to relocate","Only relocating locally"],"correct":1,"explanation":"Willing to relocate for the right opportunity."},{"sentence":"I have led several successful projects that increased sales by 20%.","question":"What was the result of their projects?","options":["Reduced costs","Increased sales by 20%","Improved customer service"],"correct":1,"explanation":"Increased sales by 20%."},{"sentence":"My previous role involved managing a team of five.","question":"How many people did they manage?","options":["Three","Five","Ten"],"correct":1,"explanation":"Managed a team of five."},{"sentence":"I am passionate about developing innovative marketing strategies.","question":"What are they passionate about?","options":["Sales techniques","Innovative marketing strategies","Customer service"],"correct":1,"explanation":"Passionate about developing innovative marketing strategies."},{"sentence":"I have a strong understanding of market research and analysis.","question":"What is their expertise?","options":["Graphic Design","Market research and analysis","Financial Accounting"],"correct":1,"explanation":"Strong understanding of market research and analysis."},{"sentence":"I enjoy collaborating with others to achieve team goals.","question":"What do they enjoy?","options":["Working alone","Collaborating with others","Managing projects"],"correct":1,"explanation":"Enjoy collaborating with others."},{"sentence":"I have excellent time management and organizational skills.","question":"What skills do they have?","options":["Time management and organizational skills","Technical skills","Creative skills"],"correct":0,"explanation":"Excellent time management and organizational skills."},{"sentence":"I am looking forward to the opportunity to discuss my qualifications.","question":"What are they looking forward to?","options":["Discussing qualifications","Receiving feedback","Starting the job immediately"],"correct":0,"explanation":"Looking forward to discussing qualifications."},{"sentence":"I have completed internships that enhanced my skills in project management.","question":"What did their internships help them with?","options":["Customer service","Project management","Sales"],"correct":1,"explanation":"Enhanced skills in project management."},{"sentence":"I am committed to continuous learning and professional development.","question":"What is their commitment?","options":["Continuous learning","Networking","Sales experience"],"correct":0,"explanation":"Committed to continuous learning."},{"sentence":"I thrive in fast-paced environments and can adapt quickly.","question":"What kind of environments do they thrive in?","options":["Slow-paced","Fast-paced","Office environments"],"correct":1,"explanation":"Thrive in fast-paced environments."}]}', 12),
('en', 'A2', 'reading', 'Healthy Living Tips', 'Short advice snippets.', '{"type":"read_and_choose","instructions":"Find the health advice.","exercises":[{"sentence":"Drinking eight glasses of water every day keeps you hydrated.","question":"How much water is recommended?","options":["4 glasses","8 glasses","12 glasses"],"correct":1,"explanation":"Eight glasses."},{"sentence":"Walking for thirty minutes can improve your mood and energy.","question":"How long should you walk?","options":["10 mins","30 mins","1 hour"],"correct":1,"explanation":"Thirty minutes."},{"sentence":"Eating more greens, like spinach and broccoli, is good for you.","question":"Which veg is mentioned?","options":["Carrots","Broccoli","Corn"],"correct":1,"explanation":"Spinach and broccoli."},{"sentence":"Try to sleep at least seven hours for a better brain.","question":"Minimum sleep?","options":["5 hours","7 hours","9 hours"],"correct":1,"explanation":"At least seven hours."},{"sentence":"Reducing sugar helps to prevent many health problems.","question":"What should be reduced?","options":["Water","Sugar","Salt"],"correct":1,"explanation":"Reducing sugar."},{"sentence":"Getting at least seven hours of sleep each night is important for overall health.","question":"How many hours of sleep are recommended?","options":["5 hours","7 hours","9 hours"],"correct":1,"explanation":"At least seven hours."},{"sentence":"Regular exercise can help reduce stress and improve mental health.","question":"What does regular exercise help with?","options":["Weight loss","Reducing stress","Building muscle"],"correct":1,"explanation":"It helps reduce stress."},{"sentence":"Limiting sugar intake can lower your risk of developing diabetes.","question":"What should you limit to lower diabetes risk?","options":["Salt","Sugar","Fat"],"correct":1,"explanation":"Limiting sugar intake."},{"sentence":"Eating a variety of fruits and vegetables provides essential nutrients.","question":"What should you eat for essential nutrients?","options":["Processed foods","Fruits and vegetables","Meat only"],"correct":1,"explanation":"Fruits and vegetables."},{"sentence":"Taking breaks during work can increase productivity and focus.","question":"What can taking breaks improve?","options":["Sleep","Productivity","Social life"],"correct":1,"explanation":"It increases productivity."},{"sentence":"Practicing mindfulness can help reduce anxiety and improve mental clarity.","question":"What does mindfulness help reduce?","options":["Anxiety","Happiness","Physical strength"],"correct":0,"explanation":"It helps reduce anxiety."},{"sentence":"Regular check-ups with a doctor can catch health issues early.","question":"What can regular check-ups do?","options":["Make you healthier","Catch health issues early","Cost a lot of money"],"correct":1,"explanation":"They can catch health issues early."},{"sentence":"Maintaining a balanced diet can help control weight.","question":"What does a balanced diet help with?","options":["Controlling weight","Eating more junk food","Losing muscle"],"correct":0,"explanation":"It helps control weight."},{"sentence":"Staying physically active can improve heart health.","question":"What can physical activity improve?","options":["Heart health","Skin appearance","Hair growth"],"correct":0,"explanation":"It improves heart health."},{"sentence":"Finding time for hobbies can help boost your mood.","question":"What can hobbies boost?","options":["Mood","Stress","Fatigue"],"correct":0,"explanation":"Hobbies can boost your mood."},{"sentence":"Limiting screen time before bed can improve sleep quality.","question":"What should you limit before bed?","options":["Reading","Screen time","Exercise"],"correct":1,"explanation":"Limit screen time."},{"sentence":"Eating breakfast can kickstart your metabolism for the day.","question":"What meal can kickstart your metabolism?","options":["Lunch","Dinner","Breakfast"],"correct":2,"explanation":"Breakfast can kickstart it."},{"sentence":"Hydration is key to maintaining energy levels throughout the day.","question":"What is key to maintaining energy levels?","options":["Hydration","Sleeping","Eating less"],"correct":0,"explanation":"Hydration is key."},{"sentence":"Practicing gratitude can enhance your overall well-being.","question":"What can practicing gratitude enhance?","options":["Overall well-being","Financial status","Physical strength"],"correct":0,"explanation":"It enhances overall well-being."},{"sentence":"Connecting with friends and family can improve mental health.","question":"What can improve mental health?","options":["Isolation","Connecting with friends and family","Working alone"],"correct":1,"explanation":"Connecting with friends and family."}]}', 13),
('en', 'A2', 'reading', 'A Day in London', 'City tour itinerary.', '{"type":"read_and_choose","instructions":"Sequence of the day.","exercises":[{"sentence":"We started the day by visiting the British Museum at 10am.","question":"Arrival time?","options":["9am","10am","11bit"],"correct":1,"explanation":"10am."},{"sentence":"Later, we walked across the bridge to see Big Ben.","question":"What did they see next?","options":["A park","Big Ben","The palace"],"correct":1,"explanation":"To see Big Ben."},{"sentence":"For lunch, we found a traditional pub and had fish and chips.","question":"What was the lunch?","options":["Pasta","Pizza","Fish and chips"],"correct":2,"explanation":"Fish and chips."},{"sentence":"In the afternoon, we took a boat trip on the River Thames.","question":"How did they travel in the afternoon?","options":["By bus","By boat","By foot"],"correct":1,"explanation":"Took a boat trip."},{"sentence":"We finished the day watching a musical in the West End.","question":"Where was the final activity?","options":["East End","West End","North London"],"correct":1,"explanation":"West End."},{"sentence":"In the morning, we enjoyed a delicious breakfast at a local café.","question":"What meal did they have in the morning?","options":["Lunch","Dinner","Breakfast"],"correct":2,"explanation":"Breakfast."},{"sentence":"After breakfast, we took a bus tour around the city.","question":"What mode of transportation did they use?","options":["Bike","Car","Bus"],"correct":2,"explanation":"They took a bus."},{"sentence":"Next, we visited the Tower of London and learned about its history.","question":"What did they learn about?","options":["Art","History","Science"],"correct":1,"explanation":"They learned about its history."},{"sentence":"In the afternoon, we stopped by a market and bought some souvenirs.","question":"What did they buy at the market?","options":["Food","Souvenirs","Clothes"],"correct":1,"explanation":"They bought souvenirs."},{"sentence":"We had a lovely dinner at a restaurant by the river.","question":"Where did they have dinner?","options":["At home","At a restaurant","In a park"],"correct":1,"explanation":"At a restaurant."},{"sentence":"After dinner, we watched a play at a nearby theater.","question":"What did they do after dinner?","options":["Go shopping","Watch a play","Visit friends"],"correct":1,"explanation":"They watched a play."},{"sentence":"Before going to bed, we enjoyed some ice cream.","question":"What dessert did they have?","options":["Cake","Ice cream","Cookies"],"correct":1,"explanation":"They enjoyed ice cream."},{"sentence":"In the late morning, we went to the Natural History Museum.","question":"What time of day did they visit the museum?","options":["Early morning","Late morning","Afternoon"],"correct":1,"explanation":"They went in the late morning."},{"sentence":"We spent some time relaxing in a park after the museum.","question":"What did they do after the museum?","options":["Go shopping","Relax in a park","Visit a friend"],"correct":1,"explanation":"They relaxed in a park."},{"sentence":"At sunset, we took pictures of the beautiful skyline.","question":"What did they take pictures of?","options":["Nature","The skyline","People"],"correct":1,"explanation":"They took pictures of the skyline."},{"sentence":"We ended the day with a stroll along the river.","question":"How did they end the day?","options":["With a walk","With a movie","With a game"],"correct":0,"explanation":"They ended the day with a stroll."},{"sentence":"In the early evening, we met some friends for coffee.","question":"What did they meet friends for?","options":["Dinner","Coffee","Drinks"],"correct":1,"explanation":"They met for coffee."},{"sentence":"We also visited a famous art gallery during our day.","question":"What type of place did they visit?","options":["Art gallery","Museum","Zoo"],"correct":0,"explanation":"They visited an art gallery."},{"sentence":"To start our adventure, we took a guided city tour in the morning.","question":"What kind of tour did they take?","options":["Self-guided","Guided city tour","Nature tour"],"correct":1,"explanation":"They took a guided city tour."},{"sentence":"Finally, we returned to our hotel to rest after a long day.","question":"Where did they go to rest?","options":["Home","Hotel","Restaurant"],"correct":1,"explanation":"They returned to their hotel."}]}', 14),
('en', 'A2', 'reading', 'Environment Report', 'Simple environmental facts.', '{"type":"read_and_choose","instructions":"Find the environment info.","exercises":[{"sentence":"Recycling paper and plastic helps to save our forests and oceans.","question":"What helps save forests?","options":["Paper recycling","Driving","Cooking"],"correct":0,"explanation":"Recycling paper."},{"sentence":"Using less electricity can lower your monthly bills and carbon footprint.","question":"Benefit of less electricity?","options":["More noise","Lower bills","Higher taxes"],"correct":1,"explanation":"Lower bills."},{"sentence":"Planting trees provides more oxygen and homes for birds.","question":"What do trees provide?","options":["Only heat","Oxygen/Homes","Food"],"correct":1,"explanation":"Oxygen and homes."},{"sentence":"Biking to work is a great way to stay fit and help the planet.","question":"Why bike?","options":["It''s slow","Stay fit/Help planet","Cheap cars"],"correct":1,"explanation":"Stay fit and help planet."},{"sentence":"Avoid using plastic bags and bring your own cloth bag.","question":"What is the recommendation?","options":["Use more plastic","Use cloth bags"],"correct":1,"explanation":"Bring your own cloth bag."},{"sentence":"Reducing plastic use decreases pollution in our oceans.","question":"What does reducing plastic use decrease?","options":["Water levels","Pollution","Fish populations"],"correct":1,"explanation":"Decreases pollution."},{"sentence":"Composting food scraps enriches the soil and reduces waste.","question":"Benefit of composting?","options":["More trash","Enriched soil","Less food"],"correct":1,"explanation":"Enriches the soil."},{"sentence":"Using public transport can reduce traffic congestion and air pollution.","question":"What does public transport help reduce?","options":["Traffic congestion","Cost of cars","Fuel prices"],"correct":0,"explanation":"Reduces traffic congestion."},{"sentence":"Switching to LED bulbs saves energy and lasts longer than traditional bulbs.","question":"Advantage of LED bulbs?","options":["More heat","Saves energy","Less light"],"correct":1,"explanation":"Saves energy."},{"sentence":"Eating locally grown food reduces the carbon footprint from transportation.","question":"What does local food help reduce?","options":["Carbon footprint","Food variety","Cooking time"],"correct":0,"explanation":"Reduces carbon footprint."},{"sentence":"Water conservation helps to save our water resources for future generations.","question":"Purpose of water conservation?","options":["To waste water","To save resources","To increase bills"],"correct":1,"explanation":"Helps save resources."},{"sentence":"Using reusable bags cuts down on single-use plastic waste.","question":"What do reusable bags help reduce?","options":["Plastic waste","Shopping time","Bag variety"],"correct":0,"explanation":"Cuts down on plastic waste."},{"sentence":"Installing solar panels can lower electricity costs and reduce reliance on fossil fuels.","question":"Benefit of solar panels?","options":["Higher costs","Lower electricity costs","More fossil fuel use"],"correct":1,"explanation":"Lowers electricity costs."},{"sentence":"Wildlife conservation protects endangered species and their habitats.","question":"What does wildlife conservation protect?","options":["Endangered species","Urban areas","Farms"],"correct":0,"explanation":"Protects endangered species."},{"sentence":"Biking instead of driving reduces greenhouse gas emissions.","question":"What does biking help reduce?","options":["Greenhouse gas emissions","Exercise time","Fuel consumption"],"correct":0,"explanation":"Reduces greenhouse gas emissions."},{"sentence":"Using natural cleaning products is better for the environment and our health.","question":"Advantage of natural cleaning products?","options":["Harmful chemicals","Better for health","Higher prices"],"correct":1,"explanation":"Better for health."},{"sentence":"Educating others about sustainability increases awareness and encourages eco-friendly practices.","question":"What does education about sustainability do?","options":["Decreases awareness","Increases awareness","Reduces interest"],"correct":1,"explanation":"Increases awareness."},{"sentence":"Planting native plants supports local wildlife and requires less water.","question":"Benefit of native plants?","options":["More water usage","Supports wildlife","Less food for animals"],"correct":1,"explanation":"Supports local wildlife."},{"sentence":"Participating in clean-up events helps to restore natural habitats and beautify communities.","question":"What do clean-up events help restore?","options":["Natural habitats","Urban development","Public transport"],"correct":0,"explanation":"Helps restore natural habitats."},{"sentence":"Sustainable farming practices protect soil health and promote biodiversity.","question":"What do sustainable farming practices protect?","options":["Soil health","Pesticide use","Crop production"],"correct":0,"explanation":"Protect soil health."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'writing', 'Connectors: And, But, So', 'Combine sentences correctly.', '{"type":"type_word","instructions":"Type the correct connector.","exercises":[{"prompt":"I was hungry, [and/but] I ate a sandwich.","expected":"so","hint":"Result of being hungry."},{"prompt":"He likes coffee, [and/but] she likes tea.","expected":"but","hint":"Showing contrast."},{"prompt":"I bought milk [and/but] bread.","expected":"and","hint":"Adding items."},{"prompt":"It was raining, [so/but] we didn''t go out.","expected":"so","hint":"Consequence."},{"prompt":"The movie was long [and/but] interesting.","expected":"but","hint":"Opposite qualities."},{"prompt":"She studied hard, [so/but] she failed the exam.","expected":"but","hint":"Showing contrast between expectation and reality."},{"prompt":"I enjoy hiking, [or/but] I prefer swimming.","expected":"but","hint":"Indicating a preference."},{"prompt":"He can play the guitar [and/or] the piano.","expected":"and","hint":"Adding skills."},{"prompt":"They went to the beach, [so/but] it started raining.","expected":"but","hint":"Showing an unexpected situation."},{"prompt":"I have a meeting [and/but] I can''t attend.","expected":"but","hint":"Contrasting two statements."},{"prompt":"I will go shopping [if/unless] I finish my work.","expected":"if","hint":"Condition for an action."},{"prompt":"She loves to dance, [but/and] she doesn''t like singing.","expected":"but","hint":"Showing contrast."},{"prompt":"You can have pizza [or/so] pasta for dinner.","expected":"or","hint":"Offering a choice."},{"prompt":"He forgot his umbrella, [so/but] he got wet.","expected":"so","hint":"Result of forgetting."},{"prompt":"I need to study [for/if] the test.","expected":"for","hint":"Indicating purpose."},{"prompt":"She can go to the party, [but/and] she has to leave early.","expected":"but","hint":"Contrasting two statements."},{"prompt":"I will call you [when/unless] I arrive.","expected":"when","hint":"Indicating a time condition."},{"prompt":"He is tired, [so/but] he will go to bed early.","expected":"so","hint":"Result of being tired."},{"prompt":"You should eat healthy food [and/but] exercise regularly.","expected":"and","hint":"Adding recommendations."},{"prompt":"It was cold outside, [so/but] we stayed indoors.","expected":"so","hint":"Result of the weather."}]}', 11),
('en', 'A2', 'writing', 'Present Continuous', 'Describe what is happening now.', '{"type":"type_word","instructions":"Type the -ing form.","exercises":[{"prompt":"I am [read] a book.","expected":"reading","hint":"Ongoing action."},{"prompt":"They are [play] football.","expected":"playing","hint":"Group action."},{"prompt":"She is [dance] in the room.","expected":"dancing","hint":"Movement."},{"prompt":"We are [wait] for the bus.","expected":"waiting","hint":"Expectation."},{"prompt":"He is [cook] dinner.","expected":"cooking","hint":"Kitchen action."},{"prompt":"He is [cook] dinner.","expected":"cooking","hint":"Preparing food."},{"prompt":"We are [swim] in the pool.","expected":"swimming","hint":"Water activity."},{"prompt":"You are [write] a letter.","expected":"writing","hint":"Creating text."},{"prompt":"They are [watch] a movie.","expected":"watching","hint":"Viewing entertainment."},{"prompt":"The baby is [cry] loudly.","expected":"crying","hint":"Expressing emotion."},{"prompt":"I am [sing] a song.","expected":"singing","hint":"Vocal performance."},{"prompt":"She is [paint] a picture.","expected":"painting","hint":"Artistic activity."},{"prompt":"We are [explore] the city.","expected":"exploring","hint":"Discovering new places."},{"prompt":"He is [fix] the car.","expected":"fixing","hint":"Repairing something."},{"prompt":"You are [jog] in the park.","expected":"jogging","hint":"Running slowly."},{"prompt":"They are [study] for the exam.","expected":"studying","hint":"Learning material."},{"prompt":"I am [call] my friend.","expected":"calling","hint":"Telephoning someone."},{"prompt":"She is [walk] to school.","expected":"walking","hint":"Moving on foot."},{"prompt":"We are [shop] for groceries.","expected":"shopping","hint":"Buying items."},{"prompt":"He is [train] for the marathon.","expected":"training","hint":"Preparing for an event."}]}', 12),
('en', 'A2', 'writing', 'Simple Past Tense', 'Change verbs to past tense.', '{"type":"type_word","instructions":"Type the past form.","exercises":[{"prompt":"Yesterday I [walk] to work.","expected":"walked","hint":"Regular past."},{"prompt":"I [buy] a new phone.","expected":"bought","hint":"Irregular past."},{"prompt":"She [see] a cat.","expected":"saw","hint":"Irregular sight."},{"prompt":"We [eat] pizza.","expected":"ate","hint":"Irregular food verb."},{"prompt":"They [play] games.","expected":"played","hint":"Regular past."},{"prompt":"Last week I [visit] my grandparents.","expected":"visited","hint":"Regular past."},{"prompt":"He [go] to the concert last night.","expected":"went","hint":"Irregular past."},{"prompt":"They [make] a cake for the party.","expected":"made","hint":"Irregular past."},{"prompt":"We [play] soccer yesterday.","expected":"played","hint":"Regular past."},{"prompt":"She [take] a lot of photos.","expected":"took","hint":"Irregular take."},{"prompt":"I [find] my keys under the couch.","expected":"found","hint":"Irregular past."},{"prompt":"He [say] hello to everyone.","expected":"said","hint":"Irregular say."},{"prompt":"They [help] me with my homework.","expected":"helped","hint":"Regular past."},{"prompt":"She [feel] happy about the news.","expected":"felt","hint":"Irregular feel."},{"prompt":"I [give] him a gift.","expected":"gave","hint":"Irregular give."},{"prompt":"We [talk] for hours last night.","expected":"talked","hint":"Regular past."},{"prompt":"He [know] the answer to the question.","expected":"knew","hint":"Irregular know."},{"prompt":"They [see] a movie together.","expected":"saw","hint":"Irregular sight."},{"prompt":"I [read] that book last year.","expected":"read","hint":"Irregular read (pronounced ''red'')."},{"prompt":"She [write] a letter to her friend.","expected":"wrote","hint":"Irregular write."}]}', 13),
('en', 'A2', 'writing', 'Comparison Time', 'Use comparatives correctly.', '{"type":"type_word","instructions":"Type the comparative form.","exercises":[{"prompt":"London is [big] than Oxford.","expected":"bigger","hint":"Double the ''g''."},{"prompt":"The sun is [hot] than the moon.","expected":"hotter","hint":"Double the ''t''."},{"prompt":"This book is [good] than that one.","expected":"better","hint":"Irregular form."},{"prompt":"I am [tall] than my brother.","expected":"taller","hint":"Standard -er."},{"prompt":"Traveling by train is [fast] than by car.","expected":"faster","hint":"Standard -er."},{"prompt":"This test is [easy] than the last one.","expected":"easier","hint":"Double the ''s''."},{"prompt":"My house is [small] than yours.","expected":"smaller","hint":"Double the ''l''."},{"prompt":"She runs [fast] than her brother.","expected":"faster","hint":"Double the ''s''."},{"prompt":"This puzzle is [difficult] than I expected.","expected":"more difficult","hint":"Use ''more'' for longer adjectives."},{"prompt":"The blue car is [cheap] than the red one.","expected":"cheaper","hint":"Double the ''e''."},{"prompt":"This movie is [interesting] than the last one.","expected":"more interesting","hint":"Use ''more'' for longer adjectives."},{"prompt":"My sister is [young] than I am.","expected":"younger","hint":"Double the ''g''."},{"prompt":"Today is [cold] than yesterday.","expected":"colder","hint":"Double the ''d''."},{"prompt":"This phone is [expensive] than that one.","expected":"more expensive","hint":"Use ''more'' for longer adjectives."},{"prompt":"The Nile is [long] than the Amazon.","expected":"longer","hint":"Double the ''g''."},{"prompt":"She is [happy] than before.","expected":"happier","hint":"Double the ''p''."},{"prompt":"This exercise is [boring] than I thought.","expected":"more boring","hint":"Use ''more'' for longer adjectives."},{"prompt":"His jokes are [funny] than hers.","expected":"funnier","hint":"Double the ''n''."},{"prompt":"This meal is [tasty] than the last one.","expected":"tastier","hint":"Double the ''t''."},{"prompt":"The book is [thick] than the magazine.","expected":"thicker","hint":"Double the ''k''."}]}', 14),
('en', 'A2', 'writing', 'Quantifiers', 'Few, many, much, some.', '{"type":"type_word","instructions":"Type the quantifier.","exercises":[{"prompt":"There is [many/much] water in the glass.","expected":"much","hint":"Uncountable noun."},{"prompt":"I have [many/much] friends.","expected":"many","hint":"Countable noun."},{"prompt":"She needs [some] help.","expected":"some","hint":"Positive request."},{"prompt":"There are a [few] apples left.","expected":"few","hint":"Small countable number."},{"prompt":"Do you have [any] sugar?","expected":"any","hint":"Question form."},{"prompt":"There are [few/little] cookies left in the jar.","expected":"few","hint":"Countable noun."},{"prompt":"We have [a lot of/little] time to finish the project.","expected":"a lot of","hint":"Positive quantity."},{"prompt":"I need [much/many] information for my report.","expected":"much","hint":"Uncountable noun."},{"prompt":"He has [a few/a little] money saved for the trip.","expected":"a little","hint":"Uncountable noun."},{"prompt":"There are [several/much] options available.","expected":"several","hint":"Countable noun."},{"prompt":"She drank [a lot of/many] juice at the party.","expected":"a lot of","hint":"Uncountable noun."},{"prompt":"I can see [many/much] stars in the sky tonight.","expected":"many","hint":"Countable noun."},{"prompt":"He has [little/many] patience with the kids.","expected":"little","hint":"Uncountable noun."},{"prompt":"There is [few/little] sugar in my coffee.","expected":"little","hint":"Uncountable noun."},{"prompt":"We received [a few/much] complaints about the service.","expected":"a few","hint":"Countable noun."},{"prompt":"She has [some/any] friends in the city.","expected":"some","hint":"Positive statement."},{"prompt":"I need [a little/many] help with my homework.","expected":"a little","hint":"Uncountable noun."},{"prompt":"There are [a lot of/much] fish in the sea.","expected":"a lot of","hint":"Countable noun."},{"prompt":"He has [little/many] experience in this field.","expected":"little","hint":"Uncountable noun."},{"prompt":"They have [some/much] exciting news to share.","expected":"some","hint":"Positive statement."}]}', 15);
